import javax.swing.ImageIcon;
import java.awt.Image;
import java.util.Base64;
import java.util.HashMap;
import java.util.Map;

class FoodImages {
    private static final Map<String,ImageIcon> CACHE = new HashMap<>();
    private static final Map<String,String> B64 = new HashMap<>();
    static {
        B64.put("cheeseburger", "");
        B64.put("classic_burger", "");
        B64.put("veggie_burger", "");
        B64.put("mushroom_burger", "");
        B64.put("spicy_burger", "");
        B64.put("bacon_burger", "");
        B64.put("bbq_burger", "");
        B64.put("crispy_chicken", "");
        B64.put("french_fries", "");
        B64.put("onion_rings", "");
        B64.put("coleslaw", "");
        B64.put("garlic_bread", "");
        B64.put("corn_cob", "");
        B64.put("sweet_potato_fries", "");
        B64.put("soda", "");
        B64.put("lemonade", "");
        B64.put("iced_tea", "");
        B64.put("orange_juice", "");
        B64.put("coffee", "");
        B64.put("milkshake", "");
        B64.put("caesar_salad", "");
        B64.put("greek_salad", "");
        B64.put("garden_salad", "");
        B64.put("nicoise_salad", "");
        B64.put("caprese", "");
        B64.put("choc_cake", "");
        B64.put("ice_cream", "");
        B64.put("cheesecake", "");
        B64.put("brownie", "");
        B64.put("fruit_salad", "");
        B64.put("discount", "");
        B64.put("happy_hour", "");
        B64.put("loyalty", "");
        B64.put("manager_comp", "");
    }

    static ImageIcon get(String key, int w, int h) {
        String ck = key+w+"x"+h;
        if (CACHE.containsKey(ck)) return CACHE.get(ck);
        String b64 = B64.get(key);
        if (b64 == null) return null;
        try {
            byte[] bytes = Base64.getDecoder().decode(b64);
            Image img = new javax.swing.ImageIcon(bytes).getImage();
            Image scaled = img.getScaledInstance(w, h, Image.SCALE_SMOOTH);
            ImageIcon icon = new ImageIcon(scaled);
            CACHE.put(ck, icon);
            return icon;
        } catch (Exception e) { return null; }
    }
}